/* RTOS task notification API */
#ifndef RTOS_NOTIFY_H
#define RTOS_NOTIFY_H

#include <stdint.h>

typedef void *task_handle_t;

/* Send a notification value to a task */
void rtos_task_notify(task_handle_t task, uint32_t value);

/* Wait for a notification, returns the received value */
uint32_t rtos_task_notify_wait(uint32_t timeout_ms);

/* Clear pending notification */
void rtos_task_notify_clear(task_handle_t task);

#endif

/* Typical caller */
void producer_task(void *arg) {
    task_handle_t consumer = (task_handle_t)arg;
    rtos_task_notify(consumer, 0xDEADBEEF);
}

after_code:
/* RTOS task notification API */
#ifndef RTOS_NOTIFY_H
#define RTOS_NOTIFY_H

#include <stdint.h>

typedef void *task_handle_t;

typedef enum {
    NOTIFY_SET_BITS   = 0,
    NOTIFY_OVERWRITE  = 1,
    NOTIFY_INCREMENT  = 2
} notify_action_t;

/* Send a notification value to a task — action parameter added */
void rtos_task_notify(task_handle_t task, uint32_t value, notify_action_t action);

/* Wait for a notification, returns the received value */
uint32_t rtos_task_notify_wait(uint32_t timeout_ms);

/* Clear pending notification */
void rtos_task_notify_clear(task_handle_t task);

#endif

/* Typical caller — now fails to compile without action argument */
void producer_task(void *arg) {
    task_handle_t consumer = (task_handle_t)arg;
    rtos_task_notify(consumer, 0xDEADBEEF, NOTIFY_SET_BITS);
}

